import React, { useMemo } from 'react';
import PropTypes from 'prop-types';
import { navigate, useIntl } from 'gatsby-plugin-intl';
import { graphql } from 'gatsby';
import { makeStyles } from '@material-ui/core/styles';
import { Typography } from '@material-ui/core';

// Utils
import { getAlternateLangLinks } from '../utils/gatsby-frontend-helpers';

// Components
import Layout from '../components/Layout';
import SEO from '../components/SEO';
import SimplePostsList from '../components/SimplePostsList';
import CustomPagination from '../components/CustomPagination';

const useStyles = makeStyles((theme) => ({
    simplePostsListWrapper: {
        marginBottom: '10px',
    },
    archiveText: {
        margin: '10px 0',
    },
}));

const Archive = ({
    data,
    location,
    pageContext,
}) => {
    const {
        posts,
        robots,
        totalPageNumber,
        currentPageNumber,
    } = pageContext;

    const intl = useIntl();
    const classes = useStyles();
    let title = intl.formatMessage({ id: 'archive' });

    if (currentPageNumber > 1) {
        const page = intl.formatMessage({ id: 'page' });
        title = `${title} - ${page} ${currentPageNumber}`;
    }

    const alternateLangLinks = useMemo(
        () => getAlternateLangLinks(pageContext, data.site.siteMetadata.siteUrl),
        [data.site.siteMetadata.siteUrl, pageContext]
    );
    const postsForLanguage = useMemo(() => posts.filter(
        (post) => post.node.fields.locale === intl.locale
    ), [intl.locale, posts]);

    return (
        <Layout>
            <SEO
                lang={intl.locale}
                pathname={location?.pathname}
                title={title}
                keywords={[
                    intl.formatMessage({ id: 'seo_keywords.archive' }),
                    intl.formatMessage({ id: 'seo_keywords.personal_blog' }),
                ]}
                alternateLangLinks={alternateLangLinks}
                robots={robots}
            />
            <Typography
                className={classes.archiveText}
                color="textPrimary"
                variant="h4"
            >
                {intl.formatMessage({ id: 'archive' })}
            </Typography>
            <SimplePostsList
                className={classes.simplePostsListWrapper}
                posts={postsForLanguage}
                locale={intl.locale}
            />
            {totalPageNumber && (
                <CustomPagination
                    currentPageNumber={currentPageNumber}
                    totalPageNumber={totalPageNumber}
                    onChange={(event, pageNumber) => {
                        navigate(`/archive/${pageNumber}`);
                    }}
                />
            )}
        </Layout>
    );
};

Archive.propTypes = {
    data: PropTypes.shape({
        allMarkdownRemark: PropTypes.shape({
            edges: PropTypes.arrayOf(PropTypes.object.isRequired).isRequired,
        }).isRequired,
        site: PropTypes.shape({
            siteMetadata: PropTypes.shape({
                siteUrl: PropTypes.string.isRequired,
            }).isRequired,
        }).isRequired,
    }).isRequired,
};

export default Archive;

export const pageQuery = graphql`
    query Archive($locale: String) {
        site {
            siteMetadata {
                siteUrl
            }
        }
        allMarkdownRemark(
            filter: {
                fields: { locale: { eq: $locale } }
                frontmatter: { show: { eq: true } }
            }
            sort: { fields: [frontmatter___date], order: DESC }
        ) {
            edges {
                node {
                    excerpt(pruneLength: 60)
                    fields {
                        slug
                        path
                        locale
                        readingTime {
                            minutes
                        }
                    }
                    frontmatter {
                        date
                        title
                        hideExcerpt
                    }
                }
            }
        }
    }
`;
